const data = $input.first().json;

// Captura o telefone da entrada
const rawPhone = String($input.first().json.body.buyer_phone|| '');

// Remove tudo que não for número
let cleaned = rawPhone.replace(/\D/g, '');
let ddd = null;

// Se começa com 11 dígitos e DDD válido, adiciona 55
if (/^\d{10,11}$/.test(cleaned)) {
  cleaned = '55' + cleaned;
}

// Corrige DDI duplicado se houver (ex: 5555...)
if (cleaned.startsWith('5555')) {
  cleaned = '55' + cleaned.slice(4);
}

// Se começa com "55" e tem 10 ou 11 dígitos depois, é BR válido
if (/^55\d{10,11}$/.test(cleaned)) {
  ddd = cleaned.slice(2, 4); // Extrai os dois dígitos após 55
} else {
  // Caso contrário, valida como número internacional (E.164: máx 15 dígitos)
  if (!/^\d{8,15}$/.test(cleaned)) {
    cleaned = '';
  }
}

// Retorna
return [{
  json: {
    telefoneOriginal: rawPhone,
    telefoneFormatado: cleaned,
    ddd: ddd
  }
}];
